	@Setup(Level.Trial)
	public void setup() throws Exception {
		theme = Theme.valueOf(themeName);
		query = ThemeQueryCatalog.queryFor(theme, z_queryIndex);
		expected = ThemeQueryCatalog.expectedCountFor(theme, z_queryIndex);

		dataDir = Files.createTempDirectory("rdf4j-sharded-lmdb-fed").toFile();
		manager = new LocalRepositoryManager(new File(dataDir, "manager"));
		manager.init();

		List<String> memberIds = createLmdbMembers();
		loadShardedThemeData(memberIds);

		multiRepoRepository = createMultiRepoRepository(memberIds);
		fedXRepository = createFedXRepository(memberIds);
	}

	@TearDown(Level.Trial)
	public void tearDown() throws IOException {
		try {
			if (multiRepoRepository != null) {
				multiRepoRepository.shutDown();
			}
		} finally {
			if (fedXRepository != null) {
				fedXRepository.shutDown();
			}
			if (manager != null) {
				manager.shutDown();
			}
			if (dataDir != null) {
				FileUtils.deleteDirectory(dataDir);
			}
		}
	}

	@Benchmark
	public long executeMultiRepoQuery() {
		return executeQuery(multiRepoRepository);
	}

	@Benchmark
	public long executeFedXQuery() {
		return executeQuery(fedXRepository);
	}

	private long executeQuery(Repository repository) {
		try (RepositoryConnection connection = repository.getConnection()) {
			TupleQuery tupleQuery = connection.prepareTupleQuery(query);
			tupleQuery.setMaxExecutionTime(5 * 60); // 5 minutes
			try (TupleQueryResult evaluate = connection.prepareTupleQuery(query).evaluate()) {
				long count = evaluate.stream().count();
				if (count != expected) {
					throw new IllegalStateException("Unexpected count: expected " + expected + " but got " + count);
				}
				return count;
			}

		}
	}

	private List<String> createLmdbMembers() throws Exception {
		List<String> memberIds = new ArrayList<>(STORE_COUNT);
		for (int i = 0; i < STORE_COUNT; i++) {
			String memberId = "lmdb-" + i;
			RepositoryImplConfig implConfig = new SailRepositoryConfig(new LmdbStoreConfig(TRIPLE_INDEXES));
			manager.addRepositoryConfig(new RepositoryConfig(memberId, implConfig));
			memberIds.add(memberId);
		}
		return memberIds;
	}

	private void loadShardedThemeData(List<String> memberIds) {
		List<RepositoryConnection> connections = new ArrayList<>(memberIds.size());
		try {
			for (String memberId : memberIds) {
				RepositoryConnection connection = manager.getRepository(memberId).getConnection();
				connection.begin(IsolationLevels.NONE);
				connections.add(connection);
			}

			ShardedInserter handler = new ShardedInserter(connections, new Random(SHARD_SEED));
			for (Theme datasetTheme : Theme.values()) {
				ThemeDataSetGenerator.generate(datasetTheme, handler);
			}

			for (RepositoryConnection connection : connections) {
				connection.commit();
			}
		} catch (RuntimeException e) {
			rollbackQuietly(connections);
			throw e;
		} finally {
			for (RepositoryConnection connection : connections) {
				connection.close();
			}
		}
	}

	private Repository createMultiRepoRepository(List<String> memberIds) {
		MultiRepoStoreConfig config = new MultiRepoStoreConfig();
		for (String memberId : memberIds) {
			config.addRepositoryMember(memberId);
		}

		SailRepository repository = new SailRepository(new MultiRepoStore(config));
		repository.setDataDir(new File(dataDir, "multirepo"));
		repository.setRepositoryResolver(manager);
		repository.init();
		return repository;
	}

	private Repository createFedXRepository(List<String> memberIds) {
		FedXFactory factory = FedXFactory.newFederation()
				.withRepositoryResolver(manager)
				.withFedXBaseDir(new File(dataDir, "fedx"));
		for (String memberId : memberIds) {
			factory.withResolvableEndpoint(memberId);
		}
		FedXRepository repository = factory.create();
		repository.init();
		return repository;
	}

	private void rollbackQuietly(List<RepositoryConnection> connections) {
		for (RepositoryConnection connection : connections) {
			try {
				if (connection.isActive()) {
					connection.rollback();
				}
			} catch (RuntimeException ignored) {
				// Preserve the original load failure.
			}
		}
	}

	private static final class ShardedInserter extends AbstractRDFHandler {

		private final List<RDFInserter> inserters;
		private final Random random;

		private ShardedInserter(List<RepositoryConnection> connections, Random random) {
			this.inserters = connections.stream().map(RDFInserter::new).collect(Collectors.toList());
			this.random = random;
		}

		@Override
		public void startRDF() throws RDFHandlerException {
			for (RDFInserter inserter : inserters) {
				inserter.startRDF();
			}
		}

		@Override
		public void handleNamespace(String prefix, String uri) throws RDFHandlerException {
			for (RDFInserter inserter : inserters) {
				inserter.handleNamespace(prefix, uri);
			}
		}

		@Override
		public void handleStatement(Statement statement) throws RDFHandlerException {
			inserters.get(random.nextInt(inserters.size())).handleStatement(statement);
		}

		@Override
		public void endRDF() throws RDFHandlerException {
			for (RDFInserter inserter : inserters) {
				inserter.endRDF();
			}
		}
	}
